var template = `
    <link rel="stylesheet" type="text/css" href="https://mtna.s3.amazonaws.com/rds/images/Postman/styles.css">
    <link href="https://fonts.googleapis.com/css2?family=Roboto+Mono:wght@300;400;500;700&display=swap" rel="stylesheet" />
    <style type="text/css">
        .information-label {
            color: rgba(0,0,0,0.54);
            font-family: Roboto, sans-serif;
            font-size: .75em;
            font-style: normal;
            font-weight: 900;
            letter-spacing: 1px;
            margin-top: 16px;
            text-transform: uppercase;
        }
        .item-id {
            color: rgba(0,0,0,0.54);
            font-family: 'Roboto Mono', monospace;
        }
    </style>
    <div class="rds-header">
        <h2 style="font-style: normal">Data Product</h2>
        <img style="max-width: 200px; max-height: 85px" src="https://mtna.s3.amazonaws.com/rds/images/RDS_2020/Web/Logo/RDS-Logo.png"/>
    </div>
    <hr/>
    <div id="wrapper">
      <div id="main">
        <br />
        <div class="textblock">
          <h3 id="startcontent">
            {{response.name}} <span class="item-id">[{{response.id}}]</span>
          </h3>

          {{#if response.description}}
          <h4 class="information-label">Description</h4>
          <div style="padding-left: 1.5%;" class="product-information"> 
            {{{response.description}}} 
          </div>
          {{/if}}
          {{#if response.citation}}
          <h4 class="information-label">Citation</h4>
          <div style="padding-left: 1.5%;" class="product-information">
            {{{response.citation}}}
          </div>
          {{/if}}
          {{#if response.provenance}}
          <h4 class="information-label">Provenance</h4>
          <div style="padding-left: 1.5%;" class="product-information">
            {{{response.provenance}}}
          </div>
          {{/if}}
          {{#if response.note}}
          <h4 class="information-label">Notes</h4>
          <div id="notes" style="padding-left: 1.5%;" class="product-information">
            {{{response.note}}}
          </div>
          {{/if}}
        </div>
      </div>
    </div>
`;

// Set visualizer
pm.visualizer.set(template, {
    // Pass the response body parsed as JSON as `data`
    response: pm.response.json()
});

// get the variable from the postman response
var variable = pm.response.json();

// get the frequencies formatted for amcharts
var frequencies = [];
if (variable.frequencies !== undefined) {
  var frequencySet = variable.frequencies.sets[0];
  for (const [key, value] of Object.entries(frequencySet.map)) {
    var entry = {
      key: key,
      value: value
    };
    frequencies.push(entry);
  }
}

// get the populate vs missing values formatted for am charts
var populated = [];
if (variable.summaryStatistics !== undefined) {
  var statisticSet = variable.summaryStatistics.sets[0];
  // populated entry
  populated.push({
    key: "Populated",
    value: statisticSet.populated
  });
  // missing entry
  populated.push({
    key: "Missing",
    value: statisticSet.missing
  });
}


var template = `
    <link
      rel="stylesheet"
      href="https://maxcdn.bootstrapcdn.com/bootstrap/3.4.1/css/bootstrap.min.css"
    />
    <link rel="stylesheet" type="text/css" href="https://mtna.s3.amazonaws.com/rds/images/Postman/styles.css">
    <link href="https://fonts.googleapis.com/css2?family=Roboto+Mono:wght@300;400;500;700&display=swap" rel="stylesheet" />
    <link
      href="https://fonts.googleapis.com/icon?family=Material+Icons"
      rel="stylesheet"
    />
    <style>
      #frequencyChart {
        width: 100%;
        height: 275px;
      }
      #populatedChart {
        width: 100%;
        height: 100px;
      }
    </style>
    <script src="https://ajax.googleapis.com/ajax/libs/jquery/3.5.1/jquery.min.js"></script>
    <script src="https://maxcdn.bootstrapcdn.com/bootstrap/3.4.1/js/bootstrap.min.js"></script>
    <script src="https://cdn.amcharts.com/lib/4/core.js"></script>
    <script src="https://cdn.amcharts.com/lib/4/charts.js"></script>
    <script src="https://cdn.amcharts.com/lib/4/themes/animated.js"></script>
    <script>
      pm.getData( function (error, data) {
      // Themes begin
      am4core.useTheme(am4themes_animated);
      // Themes end

      am4core.ready(function () {
        // Create Populated / Missing Chart
        var popChart = am4core.create("populatedChart", am4charts.XYChart);

        // Add data
        popChart.data = data.populated;

        // Create axes
        var populatedCategoryAxis = popChart.yAxes.push(new am4charts.CategoryAxis());
        populatedCategoryAxis.dataFields.category = "key";
        populatedCategoryAxis.renderer.grid.template.location = 0;
        populatedCategoryAxis.renderer.minGridDistance = 30;
        var populatedValueAxis = popChart.xAxes.push(new am4charts.ValueAxis());

        // Create series
        var populatedSeries = popChart.series.push(new am4charts.ColumnSeries());
        populatedSeries.columns.template.width = am4core.percent(20);
        populatedSeries.dataFields.valueX = "value";
        populatedSeries.dataFields.categoryY = "key";
        populatedSeries.name = "Populated and Missing";
        populatedSeries.columns.template.tooltipText = "{categoryY}: [bold]{valueX}[/]";
        populatedSeries.columns.template.fillOpacity = 0.8;

        // Create Frequency Chart
        var chart = am4core.create("frequencyChart", am4charts.XYChart);

        // Add data
        chart.data = data.frequencies;

        // Create axes
        var categoryAxis = chart.yAxes.push(new am4charts.CategoryAxis());
        categoryAxis.dataFields.category = "key";
        categoryAxis.renderer.grid.template.location = 0;
        categoryAxis.renderer.minGridDistance = 30;
        var valueAxis = chart.xAxes.push(new am4charts.ValueAxis());

        // Create series
        var series = chart.series.push(new am4charts.ColumnSeries());
        series.dataFields.valueX = "value";
        series.dataFields.categoryY = "key";
        series.name = "Value Frequencies";
        series.columns.template.tooltipText = "{categoryY}: [bold]{valueX}[/]";
        series.columns.template.fillOpacity = 0.8;

      });
      });
    </script>
    <div class="rds-header">
      <h2 style="font-style: normal; font">{{response.label}}</h2>
      <img style="max-width: 200px; max-height: 85px" src="https://mtna.s3.amazonaws.com/rds/images/RDS_2020/Web/Logo/RDS-Logo.png"/>
    </div>
    <hr/>
    <div style="margin: 32px">
      <h4>Details</h4>
      {{#if response.label}}
      <div style="display:flex; flex-direction: row;width: 100%; align-items: center" class="variable-detail-text">
        <mat-icon role="img" class="mat-icon notranslate material-icons mat-icon-no-color ng-star-inserted" aria-hidden="true">short_text</mat-icon>
        <div sytle="display:flex; flex-direction: column;">
          <h3>Label</h3>
          <p id="variable-label">{{{response.label}}}</p>
        </div>
      </div>
      {{/if}}
      {{#if response.description}}
      <div style="display:flex; flex-direction: row;width: 100%; align-items: center" class="variable-detail-text">
        <mat-icon role="img" class="mat-icon notranslate material-icons mat-icon-no-color ng-star-inserted" aria-hidden="true">notes</mat-icon>
        <div sytle="display:flex; flex-direction: column;">
          <h3>Description</h3>
          <p id="variable-description">{{{response.description}}}</p>
        </div>
      </div>
      {{/if}}
      {{#if response.questionText}}
      <div style="display:flex; flex-direction: row;width: 100%; align-items: center" class="variable-detail-text">
        <mat-icon role="img" class="mat-icon notranslate material-icons mat-icon-no-color ng-star-inserted" aria-hidden="true">notes</mat-icon>
        <div sytle="display:flex; flex-direction: column;">
          <h3>Question Text</h3>
          <p id="variable-description">{{{response.questionText}}}</p>
        </div>
      </div>
      {{/if}}
      <div style="display:flex; flex-direction: row;width: 100%; align-items: center" class="variable-detail-text">
        <mat-icon role="img" class="mat-icon notranslate material-icons mat-icon-no-color ng-star-inserted" aria-hidden="true">storage</mat-icon>
        <div sytle="display:flex; flex-direction: column;">
          <h3>Data Type</h3>
          <p id="variable-type">{{response.dataType}}</p>
        </div>
      </div>
      <div style="margin-top: 32px">
        {{#if response.summaryStatistics}}
        <div>
          <div>
            <h4>Populated and Missing</h4>
            <div id="populatedChart"></div>
          </div> 
        </div>
        {{/if}}
        {{#if response.frequencies}}
        <div>
          <div>
            <h4>Value Frequencies</h4>
            <div id="frequencyChart"></div>
          </div>
        </div>
        {{/if}}
      </div>
    </div>
`;

